css:
.typewriter {
  font-family: monospace;
  overflow: hidden;
  white-space: nowrap;
  border-right: 2px solid #B8FB3C;
  animation: typing 2s steps(11) infinite, blink 0.6s step-end infinite;
}
@keyframes typing {
  from { width: 0 }
  to { width: 11ch }
}
@keyframes blink {
  50% { border-color: transparent }
}

.type-delete {
  font-family: monospace;
  overflow: hidden;
  white-space: nowrap;
  border-right: 2px solid #a855f7;
  animation: type-del 4s steps(7) infinite;
}
@keyframes type-del {
  0%, 10% { width: 0 }
  40%, 60% { width: 7ch }
  90%, 100% { width: 0 }
}

.multi-type {
  font-family: monospace;
  overflow: hidden;
  white-space: nowrap;
  border-right: 3px solid #06b6d4;
  width: 0;
  animation: multi-typing 2s steps(4) forwards, blink-cursor 0.7s infinite;
}
@keyframes multi-typing {
  to { width: 4ch }
}
@keyframes blink-cursor {
  50% { border-color: transparent }
}

.gradient-sweep {
  background: linear-gradient(to right, #B8FB3C, #a855f7, #06b6d4);
  background-size: 200% auto;
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  animation: gradient-move 3s linear infinite;
}
@keyframes gradient-move {
  to { background-position: 200% center }
}

.gradient-pulse {
  background: linear-gradient(90deg, #f093fb, #f5576c, #4facfe);
  background-size: 300% 100%;
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  animation: pulse-gradient 2s ease infinite;
}
@keyframes pulse-gradient {
  0%, 100% { background-position: 0% 50% }
  50% { background-position: 100% 50% }
}

.rainbow-flow {
  background: linear-gradient(90deg, #ff0000, #ff7700, #ffff00, #00ff00, #0077ff, #8b00ff, #ff0000);
  background-size: 400% 100%;
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  animation: rainbow 4s linear infinite;
}
@keyframes rainbow {
  to { background-position: 400% 0 }
}

.neon-glow {
  color: #B8FB3C;
  animation: neon-pulse 2s ease-in-out infinite;
}
@keyframes neon-pulse {
  0%, 100% { text-shadow: 0 0 8px rgba(184,251,60,0.3) }
  50% { text-shadow: 0 0 24px rgba(184,251,60,0.6), 0 0 48px rgba(184,251,60,0.3) }
}

.flicker-glow {
  color: #06b6d4;
  animation: flicker 3s linear infinite;
}
@keyframes flicker {
  0%, 19%, 21%, 23%, 25%, 54%, 56%, 100% {
    text-shadow: 0 0 10px #06b6d4, 0 0 20px #06b6d4;
  }
  20%, 24%, 55% {
    text-shadow: none;
  }
}

.breathe-glow {
  color: #a855f7;
  animation: breathe 3s ease-in-out infinite;
}
@keyframes breathe {
  0%, 100% { text-shadow: 0 0 4px rgba(168,85,247,0.2); opacity: 0.8 }
  50% { text-shadow: 0 0 20px rgba(168,85,247,0.6), 0 0 40px rgba(168,85,247,0.3); opacity: 1 }
}

.bounce-letters span {
  display: inline-block;
  animation: bounce-up 0.6s ease infinite;
}
.bounce-letters span:nth-child(2) { animation-delay: 0.08s }
.bounce-letters span:nth-child(3) { animation-delay: 0.16s }
.bounce-letters span:nth-child(4) { animation-delay: 0.24s }
@keyframes bounce-up {
  0%, 100% { transform: translateY(0) }
  50% { transform: translateY(-12px) }
}

.bounce-scale {
  display: inline-block;
  animation: pop-bounce 1s ease infinite;
}
@keyframes pop-bounce {
  0%, 100% { transform: scale(1) }
  30% { transform: scale(1.15) }
  50% { transform: scale(0.95) }
  70% { transform: scale(1.05) }
}

.elastic-drop {
  display: inline-block;
  animation: elastic 2s ease infinite;
}
@keyframes elastic {
  0% { transform: translateY(-40px); opacity: 0 }
  30% { transform: translateY(8px) }
  50% { transform: translateY(-4px) }
  70% { transform: translateY(2px) }
  100% { transform: translateY(0); opacity: 1 }
}

.slide-reveal {
  overflow: hidden;
}
.slide-reveal span {
  display: block;
  animation: slide-in 0.8s cubic-bezier(0.4, 0, 0.2, 1) infinite;
  animation-delay: 2s;
}
@keyframes slide-in {
  from { transform: translateX(-100%) }
  to { transform: translateX(0) }
}

.slide-up {
  overflow: hidden;
}
.slide-up span {
  display: block;
  animation: rise 0.6s cubic-bezier(0.4, 0, 0.2, 1) forwards;
}
@keyframes rise {
  from { transform: translateY(100%); opacity: 0 }
  to { transform: translateY(0); opacity: 1 }
}

.split-reveal {
  position: relative;
  overflow: hidden;
}
.split-reveal::after {
  content: '';
  position: absolute;
  inset: 0;
  background: #0a0a0f;
  animation: split-wipe 1.5s ease forwards infinite;
}
@keyframes split-wipe {
  0% { transform: translateX(0) }
  100% { transform: translateX(101%) }
}

.blur-in {
  animation: blur-focus 1.2s ease infinite;
}
@keyframes blur-focus {
  0% { filter: blur(8px); opacity: 0 }
  100% { filter: blur(0); opacity: 1 }
}

.blur-wave span {
  display: inline-block;
  animation: blur-letter 2s ease infinite;
}
.blur-wave span:nth-child(2) { animation-delay: 0.1s }
.blur-wave span:nth-child(3) { animation-delay: 0.2s }
@keyframes blur-letter {
  0%, 100% { filter: blur(0) }
  50% { filter: blur(4px) }
}

.fade-in {
  animation: fade-appear 1s ease forwards;
}
@keyframes fade-appear {
  from { opacity: 0; transform: translateY(10px) }
  to { opacity: 1; transform: translateY(0) }
}

.fade-letters span {
  display: inline-block;
  opacity: 0;
  animation: letter-fade 0.4s ease forwards;
}
.fade-letters span:nth-child(2) { animation-delay: 0.1s }
.fade-letters span:nth-child(3) { animation-delay: 0.2s }
@keyframes letter-fade {
  to { opacity: 1 }
}

.fade-scale {
  animation: scale-fade 1.5s ease infinite;
}
@keyframes scale-fade {
  0% { opacity: 0; transform: scale(0.8) }
  50% { opacity: 1; transform: scale(1) }
  100% { opacity: 0; transform: scale(1.1) }
}

.wave-text span {
  display: inline-block;
  animation: wave 1.5s ease-in-out infinite;
}
.wave-text span:nth-child(2) { animation-delay: 0.1s }
.wave-text span:nth-child(3) { animation-delay: 0.2s }
@keyframes wave {
  0%, 100% { transform: translateY(0) }
  25% { transform: translateY(-8px) }
  75% { transform: translateY(4px) }
}

.color-wave span {
  display: inline-block;
  animation: color-shift 2s ease infinite;
}
.color-wave span:nth-child(2) { animation-delay: 0.15s }
.color-wave span:nth-child(3) { animation-delay: 0.3s }
@keyframes color-shift {
  0%, 100% { color: #B8FB3C }
  33% { color: #a855f7 }
  66% { color: #06b6d4 }
}

.glitch {
  position: relative;
  animation: glitch-skew 1s infinite linear;
}
.glitch::before,
.glitch::after {
  content: attr(data-text);
  position: absolute;
  top: 0; left: 0;
}
.glitch::before {
  color: #ff00c1;
  animation: glitch-1 0.5s infinite;
  clip-path: inset(40% 0 60% 0);
}
.glitch::after {
  color: #00fff9;
  animation: glitch-2 0.5s infinite;
  clip-path: inset(20% 0 40% 0);
}
@keyframes glitch-1 {
  20% { transform: translate(-2px, 2px) }
  40% { transform: translate(2px, -2px) }
  60% { transform: translate(-2px, 0) }
}
@keyframes glitch-2 {
  20% { transform: translate(2px, -2px) }
  40% { transform: translate(-2px, 2px) }
  60% { transform: translate(2px, 0) }
}

.distortion {
  animation: distort 3s infinite;
}
@keyframes distort {
  0%, 100% { text-shadow: 2px 0 #ff00c1, -2px 0 #00fff9 }
  25% { text-shadow: -2px 2px #ff00c1, 2px -2px #00fff9 }
  50% { text-shadow: 2px -2px #ff00c1, -2px 2px #00fff9 }
  75% { text-shadow: -2px 0 #ff00c1, 2px 0 #00fff9 }
}

.rotate-in {
  display: inline-block;
  animation: rotate-enter 1s ease infinite;
}
@keyframes rotate-enter {
  from { transform: rotate(-180deg); opacity: 0 }
  to { transform: rotate(0); opacity: 1 }
}

.letter-spin span {
  display: inline-block;
  animation: spin-letter 2s ease infinite;
}
.letter-spin span:nth-child(2) { animation-delay: 0.1s }
.letter-spin span:nth-child(3) { animation-delay: 0.2s }
@keyframes spin-letter {
  0%, 100% { transform: rotateY(0) }
  50% { transform: rotateY(360deg) }
}

.flip-3d {
  display: inline-block;
  animation: flip-text 2s ease infinite;
  perspective: 500px;
}
@keyframes flip-text {
  0%, 100% { transform: rotateX(0) }
  50% { transform: rotateX(180deg) }
}

.scale-in {
  display: inline-block;
  animation: grow-in 1s ease forwards;
}
@keyframes grow-in {
  from { transform: scale(0); opacity: 0 }
  to { transform: scale(1); opacity: 1 }
}

.scale-pulse {
  display: inline-block;
  animation: pulse-scale 1.5s ease infinite;
}
@keyframes pulse-scale {
  0%, 100% { transform: scale(1) }
  50% { transform: scale(1.08) }
}

.pop-letters span {
  display: inline-block;
  animation: pop-letter 0.5s ease forwards;
  transform: scale(0);
}
.pop-letters span:nth-child(2) { animation-delay: 0.1s }
.pop-letters span:nth-child(3) { animation-delay: 0.2s }
@keyframes pop-letter {
  0% { transform: scale(0) }
  70% { transform: scale(1.2) }
  100% { transform: scale(1) }
}

.shadow-lift {
  animation: lift-shadow 2s ease infinite;
}
@keyframes lift-shadow {
  0%, 100% { text-shadow: 0 2px 4px rgba(0,0,0,0.2) }
  50% { text-shadow: 0 8px 16px rgba(0,0,0,0.3); transform: translateY(-4px) }
}

.long-shadow {
  color: #fff;
  animation: long-shad 3s ease infinite;
}
@keyframes long-shad {
  0%, 100% { text-shadow: 1px 1px #0003, 2px 2px #0003, 3px 3px #0003 }
  50% { text-shadow: 2px 2px #0003, 4px 4px #0003, 6px 6px #0003, 8px 8px #0002, 10px 10px #0001 }
}

.underline-grow {
  position: relative;
  display: inline-block;
}
.underline-grow::after {
  content: '';
  position: absolute;
  bottom: -2px; left: 0;
  width: 0; height: 2px;
  background: #B8FB3C;
  animation: grow-line 2s ease infinite;
}
@keyframes grow-line {
  0% { width: 0 }
  50% { width: 100% }
  100% { width: 0 }
}

.slide-underline {
  position: relative;
  display: inline-block;
}
.slide-underline::after {
  content: '';
  position: absolute;
  bottom: -2px; left: 0;
  width: 100%; height: 2px;
  background: #a855f7;
  transform: translateX(-100%);
  animation: slide-line 2s ease infinite;
}
@keyframes slide-line {
  0% { transform: translateX(-100%) }
  50% { transform: translateX(0) }
  100% { transform: translateX(100%) }
}

.stroke-fill {
  -webkit-text-stroke: 1px #B8FB3C;
  color: transparent;
  animation: fill-stroke 3s ease infinite;
}
@keyframes fill-stroke {
  0%, 100% { color: transparent }
  50% { color: #B8FB3C }
}

.draw-outline {
  -webkit-text-stroke: 2px #06b6d4;
  color: transparent;
  animation: draw-text 2s ease infinite;
}
@keyframes draw-text {
  0% { -webkit-text-stroke-dashoffset: 100% }
  50% { color: #06b6d4 }
  100% { color: transparent }
}

.morph-blur {
  animation: morph-anim 3s ease infinite;
}
@keyframes morph-anim {
  0%, 100% { filter: blur(0); transform: scale(1) }
  25% { filter: blur(2px); transform: scale(1.02) }
  50% { filter: blur(0); transform: scale(0.98) }
  75% { filter: blur(1px); transform: scale(1.01) }
}

.scramble-shake {
  display: inline-block;
  animation: shake-text 0.3s ease infinite;
}
@keyframes shake-text {
  0% { transform: translate(0) }
  25% { transform: translate(-2px, 1px) }
  50% { transform: translate(2px, -1px) }
  75% { transform: translate(-1px, 2px) }
  100% { transform: translate(0) }
}

.jelly-wobble {
  display: inline-block;
  animation: jelly 1.5s ease infinite;
}
@keyframes jelly {
  0%, 100% { transform: scale(1, 1) }
  25% { transform: scale(0.9, 1.1) }
  50% { transform: scale(1.1, 0.9) }
  75% { transform: scale(0.95, 1.05) }
}

.stagger-reveal span {
  display: inline-block;
  opacity: 0;
  transform: translateY(20px);
  animation: stagger-up 0.5s ease forwards;
}
.stagger-reveal span:nth-child(2) { animation-delay: 0.1s }
.stagger-reveal span:nth-child(3) { animation-delay: 0.2s }
.stagger-reveal span:nth-child(4) { animation-delay: 0.3s }
.stagger-reveal span:nth-child(5) { animation-delay: 0.4s }
@keyframes stagger-up {
  to { opacity: 1; transform: translateY(0) }
}
